import { supabase } from '@/lib/supabase'
import { NextRequest, NextResponse } from 'next/server'
import * as XLSX from 'xlsx'

// 물류사 → 창고 매핑
const DISTRIBUTOR_TO_WAREHOUSE: Record<string, string> = {
  '아임웹': '드림산업',
  '스마트스토어': '드림산업',
  '본사소진': '드림산업',
  '29CM': '투민글로벌',
  'W컨셉': '투민글로벌',
  '무신사': '투민글로벌',
  'CJ온스타일': '투민글로벌'
}

export async function POST(request: NextRequest) {
  try {
    const formData = await request.formData()
    const file = formData.get('file') as File
    const warehouseParam = formData.get('warehouse') as string

    if (!file) {
      return NextResponse.json({ error: '파일이 없습니다' }, { status: 400 })
    }

    // 선택된 창고 (dream = 드림산업, tumin = 투민글로벌)
    const targetWarehouse = warehouseParam === 'tumin' ? '투민글로벌' : '드림산업'
    console.log('📦 선택된 창고:', targetWarehouse)

    // 파일명에서 날짜 추출
    // 8자리: "20260421_발주서.xlsx" → "2026-04-21"
    // 6자리: "드림산업익일발주_260511.xlsx" → "2026-05-11"
    const isValidYmd = (y: number, m: number, d: number) =>
      y >= 2020 && y <= 2035 && m >= 1 && m <= 12 && d >= 1 && d <= 31
    const filenameDate = (() => {
      // 8자리 형식 시도
      const m8 = file.name.match(/(\d{8})/)
      if (m8) {
        const s = m8[1]
        const y = parseInt(s.slice(0, 4))
        const mo = parseInt(s.slice(4, 6))
        const da = parseInt(s.slice(6, 8))
        if (isValidYmd(y, mo, da)) {
          return `${s.slice(0, 4)}-${s.slice(4, 6)}-${s.slice(6, 8)}`
        }
      }

      // 6자리 형식 시도 (260511 → 2026-05-11)
      const m6 = file.name.match(/(\d{6})/)
      if (m6) {
        const s = m6[1]
        const y = parseInt('20' + s.slice(0, 2))
        const mo = parseInt(s.slice(2, 4))
        const da = parseInt(s.slice(4, 6))
        if (isValidYmd(y, mo, da)) {
          return `${y}-${s.slice(2, 4)}-${s.slice(4, 6)}`
        }
      }

      return null
    })()
    const fallbackDate = filenameDate || new Date().toISOString().split('T')[0]
    console.log(`📅 기본 날짜 (날짜 컬럼 없는 행에 적용): ${fallbackDate}`)

    // 엑셀 파일 읽기
    const buffer = await file.arrayBuffer()
    const workbook = XLSX.read(buffer, { type: 'buffer' })
    const sheetName = workbook.SheetNames[0]
    const sheet = workbook.Sheets[sheetName]

    // 먼저 배열로 읽어서 헤더 유무 확인
    const rawData = XLSX.utils.sheet_to_json(sheet, { header: 1 }) as any[]

    // 헤더 없는 형식 감지 (드림산업: 마지막 컬럼이 6자리 날짜)
    const firstRowLastCol = rawData[0]?.[rawData[0].length - 1]
    const isNoHeaderFormat = typeof firstRowLastCol === 'number' &&
                            String(firstRowLastCol).length === 6 &&
                            rawData[0]?.length >= 13 // 드림산업은 13개 컬럼

    let data: any[]
    let isNewFormat = false

    if (isNoHeaderFormat) {
      // 헤더 없는 형식 (드림산업 익일발주서)
      console.log('📋 형식: 드림산업 익일발주서 (헤더 없음)')
      data = rawData.map(row => ({
        __index_0: row[0],  // 수령인
        __index_1: row[1],  // 전화번호
        __index_3: row[3],  // 주소
        __index_4: row[4],  // 수량
        __index_5: row[5],  // 바코드
        __index_6: row[6],  // 품명
        __index_7: row[7],  // 배송메모
        __index_8: row[8],  // 송장번호
        __index_9: row[9],  // 주문번호
        __index_12: row[12] // 날짜
      }))
      isNewFormat = true
    } else {
      // 헤더 있는 형식
      data = XLSX.utils.sheet_to_json(sheet) as any[]
      const firstRow = data[0] || {}
      const hasOrderCode = '오더코드' in firstRow || '주문코드' in firstRow
      const hasDateColumn = '날짜' in firstRow
      const hasBarcodeColumn = '__EMPTY_1' in firstRow || '__EMPTY' in firstRow
      const hasDreamKeys =
        '주문번호' in firstRow && '품명' in firstRow && '수취인' in firstRow
      // 드림 형식: (날짜+바코드) OR (주문번호+품명+수취인 헤더)
      isNewFormat = (hasDateColumn && hasBarcodeColumn && !hasOrderCode) ||
                    (hasDreamKeys && !hasOrderCode)
      console.log(`📋 파일 형식: ${isNewFormat ? '드림산업 (헤더 있음)' : '기존 발주조회'}`)
    }

    console.log(`📊 엑셀 데이터 ${data.length}개 행 읽기 완료`)

    // 유효한 바코드 목록 가져오기 (product_name까지 한 번에)
    const { data: productBarcodes } = await supabase
      .from('product_barcodes')
      .select('barcode, product_name')

    const { data: setBarcodes } = await supabase
      .from('set_barcodes')
      .select('set_barcode')

    const validProductBarcodes = new Set(productBarcodes?.map(p => p.barcode))
    const validSetBarcodes = new Set(setBarcodes?.map(s => s.set_barcode))
    const productNameMap = new Map<string, string>()
    productBarcodes?.forEach(p => {
      if (p.barcode) productNameMap.set(p.barcode, p.product_name || '')
    })

    // 바코드 별칭 로드 (포장재 차이 등으로 다른 바코드지만 같은 제품으로 집계)
    const { data: aliasRows } = await supabase
      .from('barcode_aliases')
      .select('alias_barcode, actual_barcode')

    const barcodeAliases = new Map<string, string>()
    aliasRows?.forEach(a => {
      if (a.alias_barcode && a.actual_barcode) {
        barcodeAliases.set(String(a.alias_barcode), String(a.actual_barcode))
      }
    })
    const resolveAlias = (code: string) => barcodeAliases.get(code) || code

    // 세트 구성품 전체 prefetch (루프 내 N+1 쿼리 제거)
    const { data: allCompositions } = await supabase
      .from('set_composition')
      .select('set_barcode, component_barcode, quantity')

    const setCompositionsMap = new Map<string, { product_barcode: string; quantity: number }[]>()
    allCompositions?.forEach(c => {
      if (!c.set_barcode) return
      const list = setCompositionsMap.get(c.set_barcode) || []
      list.push({ product_barcode: c.component_barcode, quantity: c.quantity })
      setCompositionsMap.set(c.set_barcode, list)
    })

    // 데이터 변환 및 검증
    const salesRecords: any[] = []
    const errors: string[] = []
    let skippedCount = 0
    let excludedCount = 0
    const uniqueOrderCodes = new Set<string>()
    const dreamOrderCodes = new Set<string>() // 드림산업 고유 주문번호 추적

    for (let i = 0; i < data.length; i++) {
      const row = data[i]

      let orderCode = ''
      let distributor = ''
      let sku = ''
      let quantity = 0
      let saleDate = ''
      let warehouse = ''

      if (isNewFormat) {
        // 신규 형식 (드림산업 익일발주건 / 발주양식)
        // 헤더 없는 경우: __index_X 사용, 헤더 있는 경우: 컬럼명 사용
        orderCode = String(row['__index_9'] || row['주문번호'] || '')
        sku = String(row['__index_5'] || row['__EMPTY'] || '').trim()
        quantity = parseInt(row['__index_4'] || row['수량'] || '0')
        warehouse = targetWarehouse // 선택된 창고

        // 빈 행(주문번호 없음) 조용히 건너뛰기 - 발주양식 하단 빈 템플릿 행 대응
        if (!orderCode) {
          continue
        }

        // 날짜 추출: 날짜 컬럼이 있으면 그 값, 없거나 비었으면 파일명/오늘 날짜 폴백
        const dateNum = String(row['__index_12'] || row['__EMPTY_1'] || row['날짜'] || '')
        if (dateNum.length === 6) {
          // 6자리: 260102
          const y = parseInt('20' + dateNum.substring(0, 2))
          const m = parseInt(dateNum.substring(2, 4))
          const d = parseInt(dateNum.substring(4, 6))
          if (!isValidYmd(y, m, d)) {
            errors.push(`행 ${i + 2}: 날짜 형식 오류 (${dateNum})`)
            continue
          }
          saleDate = `${y}-${String(m).padStart(2, '0')}-${String(d).padStart(2, '0')}`
        } else if (dateNum.length === 8) {
          // 8자리: 20260102
          const y = parseInt(dateNum.substring(0, 4))
          const m = parseInt(dateNum.substring(4, 6))
          const d = parseInt(dateNum.substring(6, 8))
          if (!isValidYmd(y, m, d)) {
            errors.push(`행 ${i + 2}: 날짜 형식 오류 (${dateNum})`)
            continue
          }
          saleDate = `${y}-${String(m).padStart(2, '0')}-${String(d).padStart(2, '0')}`
        } else {
          // 날짜 컬럼 없음/빈값 → 파일명 날짜 또는 오늘 (발주양식 송장입력 등)
          saleDate = fallbackDate
        }

        // 택배건수 계산용 (주문제작 포함)
        if (orderCode) {
          uniqueOrderCodes.add(orderCode)
          // 드림산업 송장건수 추적
          if (warehouse === '드림산업') {
            dreamOrderCodes.add(orderCode)
          }
        }

        // 배송메모에 "증정", "사은품", "협찬" 키워드가 있으면 제외
        const memo = String(row['__index_7'] || row['배송메모'] || '').trim()
        if (memo.includes('증정') || memo.includes('사은품') || memo.includes('협찬')) {
          excludedCount++
          continue
        }

        // 품명에 "협찬" 키워드가 있으면 제외 (SKU 유무와 무관)
        const productNameDream = String(row['__index_6'] || row['품명'] || '')
        if (productNameDream.includes('협찬')) {
          excludedCount++
          continue
        }

        // 바코드가 없으면 품명에서 주문제작 여부 확인
        if (!sku) {
          const productName = String(row['__index_6'] || row['품명'] || '')

          // 증정/사은품/포장재는 제외
          if (productName.includes('증정') || productName.includes('사은품') || productName.includes('포장재')) {
            excludedCount++
            continue
          }

          // 주문제작/필수입력 옵션 주문인 경우 카테고리별로 집계
          // "색상" + "디자인" 둘 다 포함되면 옵션 기반 커스텀 주문
          const hasColorAndDesign = productName.includes('색상') && productName.includes('디자인')
          if (
            productName.includes('주문제작') ||
            productName.includes('필수입력') ||
            hasColorAndDesign
          ) {
            let customCategory = ''

            if (productName.includes('미니멀')) {
              customCategory = 'CUSTOM_MINIMAL'
            } else if (productName.includes('그레인')) {
              customCategory = 'CUSTOM_GRAIN'
            } else if (productName.includes('사이잘')) {
              customCategory = 'CUSTOM_SISAL'
            } else {
              // 기타는 모두 시어서커로 분류
              customCategory = 'CUSTOM_SHEERSUCKER'
            }

            // 주문제작 레코드 추가
            salesRecords.push({
              sale_date: saleDate,
              warehouse,
              product_barcode: customCategory,
              quantity,
              order_id: null,
              is_manual: false
            })
            continue
          }

          // 주문제작도 아니고 바코드도 없으면 오류
          errors.push(`행 ${i + 1}: 바코드 없음 (품명: ${productName || '없음'})`)
          continue
        }
      } else {
        // 기존 형식 (발주조회)
        orderCode = row['오더코드'] || row['주문코드'] || row['order_code'] || ''
        distributor = row['발주 타입'] || row['물류사'] || row['distributor'] || ''
        sku = row['고유코드'] || row['SKU'] || row['sku'] || ''
        quantity = parseInt(row['수량'] || row['quantity'] || '0')

        // 협찬, 본사소진 제외
        if (distributor === '협찬' || distributor === '본사소진') {
          excludedCount++
          continue
        }

        // 배송메모에 "증정", "사은품" 키워드가 있으면 제외
        const memo = String(row['배송메모'] || row['memo'] || '').trim()
        if (memo.includes('증정') || memo.includes('사은품')) {
          excludedCount++
          continue
        }

        // 상품명에 "증정/사은품/행사/포장재" 키워드가 있으면 제외 (SKU 유무와 무관)
        const productNameEarly = String(row['판매상품명'] || row['상품명'] || row['품명'] || '')
        if (
          productNameEarly.includes('증정') ||
          productNameEarly.includes('사은품') ||
          productNameEarly.includes('행사') ||
          productNameEarly.includes('포장재')
        ) {
          excludedCount++
          continue
        }

        if (!orderCode) {
          errors.push(`행 ${i + 2}: 주문코드 누락`)
          continue
        }

        // 날짜 추출 (O20260102-00338 → 2026-01-02)
        const dateMatch = orderCode.match(/O(\d{4})(\d{2})(\d{2})/)
        if (!dateMatch) {
          errors.push(`행 ${i + 2}: 주문코드 형식 오류 (${orderCode})`)
          continue
        }

        saleDate = `${dateMatch[1]}-${dateMatch[2]}-${dateMatch[3]}`

        // 창고는 선택된 창고 사용 (발주 타입과 무관)
        warehouse = targetWarehouse

        // 택배건수 계산용 (주문제작 포함)
        if (orderCode) {
          uniqueOrderCodes.add(orderCode)
        }

        // SKU 없으면 품명에서 주문제작 여부 확인
