import { createClient } from '@supabase/supabase-js'

const supabase = createClient(
  'https://ebktoazswvtqsjrjryqk.supabase.co',
  'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImVia3RvYXpzd3Z0cXNqcmpyeXFrIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NDIzNTYzNTAsImV4cCI6MjA1NzkzMjM1MH0.td_JfiPhwoHh8gVCp-FbLgvXs7C0Crs7XVL68QCобщина'
)

async function checkOrphanUsage() {
  console.log('🔍 고아 바코드 사용 현황 검토\n')

  // 1. 고아 바코드 목록 조회
  const { data: orphans } = await supabase
    .from('set_barcodes')
    .select('set_barcode')
    .or('set_barcode.like.MCSA2%,set_barcode.like.MCSA3%,set_barcode.like.MCSA4%,set_barcode.like.MCSA5%,set_barcode.like.MCSB2%,set_barcode.like.MCSB3%,set_barcode.like.MCSB4%,set_barcode.like.MCSB5%,set_barcode.like.MCSC2%,set_barcode.like.MCSC3%,set_barcode.like.MCSC4%,set_barcode.like.MCSC5%,set_barcode.like.PCS0101%')

  const barcodes = orphans?.map(o => o.set_barcode) || []
  console.log(`📦 대상 바코드: ${barcodes.length}개`)
  console.log(barcodes.join(', '))
  console.log()

  if (barcodes.length === 0) {
    console.log('❌ 대상 바코드가 없습니다.')
    return
  }

  // 2. daily_sales 확인
  const { data: salesData, count: salesCount } = await supabase
    .from('daily_sales')
    .select('product_barcode', { count: 'exact' })
    .in('product_barcode', barcodes)

  console.log(`📊 daily_sales: ${salesCount || 0}건`)
  if (salesCount && salesCount > 0) {
    const usage = {}
    salesData?.forEach(s => {
      usage[s.product_barcode] = (usage[s.product_barcode] || 0) + 1
    })
    Object.entries(usage).forEach(([bc, cnt]) => {
      console.log(`  - ${bc}: ${cnt}건`)
    })
  }
  console.log()

  // 3. daily_shipment_data 확인
  const { data: shipmentData, count: shipmentCount } = await supabase
    .from('daily_shipment_data')
    .select('sku', { count: 'exact' })
    .in('sku', barcodes)

  console.log(`📦 daily_shipment_data: ${shipmentCount || 0}건`)
  if (shipmentCount && shipmentCount > 0) {
    const usage = {}
    shipmentData?.forEach(s => {
      usage[s.sku] = (usage[s.sku] || 0) + 1
    })
    Object.entries(usage).forEach(([bc, cnt]) => {
      console.log(`  - ${bc}: ${cnt}건`)
    })
  }
  console.log()

  // 4. manufacturer_shipment_data 확인 (품명 검색)
  const patterns = ['MCSA2', 'MCSA3', 'MCSA4', 'MCSA5', 'MCSB2', 'MCSB3', 'MCSB4', 'MCSB5', 'MCSC2', 'MCSC3', 'MCSC4', 'MCSC5', 'PCS0101']
  let mfgCount = 0
  const mfgResults = []

  for (const pattern of patterns) {
    const { data: mfgData, count } = await supabase
      .from('manufacturer_shipment_data')
      .select('product_name', { count: 'exact' })
      .ilike('product_name', `%${pattern}%`)

    if (count && count > 0) {
      mfgCount += count
      mfgResults.push({ pattern, count, samples: mfgData?.slice(0, 3) })
    }
  }

  console.log(`🏭 manufacturer_shipment_data: ${mfgCount}건`)
  if (mfgCount > 0) {
    mfgResults.forEach(r => {
      console.log(`  - ${r.pattern}: ${r.count}건`)
      r.samples?.forEach(s => console.log(`    "${s.product_name}"`))
    })
  }
