import { supabase } from '@/lib/supabase'
import ClientPage from './ClientPage'

export const dynamic = 'force-dynamic'
export const revalidate = 0

// 주차 계산 (목~수 기준)
function getWeekNumber(dateStr: string): number {
  const date = new Date(dateStr)
  const thursday = new Date(date)
  thursday.setDate(date.getDate() + (3 - date.getDay()))
  const firstThursday = new Date(thursday.getFullYear(), 0, 1)
  firstThursday.setDate(firstThursday.getDate() + (3 - firstThursday.getDay()))
  const weekNum = Math.floor((thursday.getTime() - firstThursday.getTime()) / (7 * 24 * 60 * 60 * 1000)) + 1
  return weekNum
}

export default async function ProductGroupsPage() {
  console.log('🔍 제품군별 분석 페이지 데이터 로딩 시작')

  // 1. daily_sales에서 2026년 전체 데이터 조회 (pagination, product_name join)
  const allSalesData = []

  for (let month = 1; month <= 12; month++) {
    const monthStr = `2026-${String(month).padStart(2, '0')}`
    const monthStart = `${monthStr}-01`
    const lastDay = new Date(2026, month, 0).getDate()
    const monthEnd = `${monthStr}-${String(lastDay).padStart(2, '0')}`

    let offset = 0
    const limit = 1000

    while (true) {
      const { data: monthData } = await supabase
        .from('daily_sales')
        .select(`
          *,
          product_barcodes (
            product_name,
            category
          )
        `)
        .gte('sale_date', monthStart)
        .lte('sale_date', monthEnd)
        .range(offset, offset + limit - 1)

      if (!monthData || monthData.length === 0) break

      allSalesData.push(...monthData)

      if (monthData.length < limit) break
      offset += limit
    }
  }

  console.log(`  총 조회된 판매 레코드: ${allSalesData.length}개`)

  // 2. product_name으로 제품군 분류
  const salesData: any[] = []
  const productGroups = ['미니멀러그', '그레인러그', '시어서커', '사이잘러그', '방석/쿠션', '블랭킷']

  allSalesData.forEach(record => {
    const productName = record.product_barcodes?.product_name || ''
    let group = ''

    // 충전재, 내장재, 포장재 등 부자재는 제외
    if (productName.includes('충전재') || productName.includes('내장재') ||
        productName.includes('포장재') || productName.includes('박스') ||
        productName.includes('비닐')) {
      return
    }

    // product_name으로 제품군 분류
    if (productName.includes('미니멀')) {
      group = '미니멀러그'
    } else if (productName.includes('그레인')) {
      group = '그레인러그'
    } else if (productName.includes('시어서커')) {
      group = '시어서커'
    } else if (productName.includes('사이잘')) {
      group = '사이잘러그'
    } else if (productName.includes('방석') || productName.includes('펫쿠션') || productName.includes('쿠션')) {
      group = '방석/쿠션'
    } else if (productName.includes('블랭킷')) {
      group = '블랭킷'
    }

    if (group) {
      salesData.push({ ...record, group })
    }
  })

  console.log(`  제품군 분류 완료: ${salesData.length}개`)

  // 3. 제품군별 월별/주간별 집계
  const monthlyData: Record<string, Record<number, number>> = {}
  const weeklyData: Record<string, Record<number, number>> = {}
  const totalByGroup: Record<string, number> = {}

  productGroups.forEach(group => {
    monthlyData[group] = {}
    weeklyData[group] = {}
    totalByGroup[group] = 0
  })

  salesData.forEach(record => {
    const group = record.group
    const saleDate = record.sale_date
    const quantity = parseFloat(record.quantity) || 0
    const month = parseInt(saleDate.split('-')[1])
    const week = getWeekNumber(saleDate)

    monthlyData[group][month] = (monthlyData[group][month] || 0) + quantity
    weeklyData[group][week] = (weeklyData[group][week] || 0) + quantity
    totalByGroup[group] = (totalByGroup[group] || 0) + quantity
  })

  console.log('✅ 데이터 집계 완료')
  console.log('제품군별 총계:', totalByGroup)

  return (
    <main className="min-h-screen" style={{ background: '#F6F6F2' }}>
      <div className="max-w-full mx-auto px-8 py-10">
        {/* 페이지 헤더 */}
        <div className="mb-8">
          <h1 className="text-3xl font-bold tracking-tight mb-2" style={{ color: '#212121' }}>
            📊 제품군별 판매 분석
          </h1>
          <p className="text-sm" style={{ color: '#999999' }}>
            미니멀러그, 그레인러그, 시어서커, 사이잘러그 판매량 추이
          </p>
        </div>

        {/* 클라이언트 페이지 */}
        <ClientPage
          monthlyData={monthlyData}
          weeklyData={weeklyData}
          totalByGroup={totalByGroup}
        />
      </div>
    </main>
  )
}

'use client'

import { useState } from 'react'

interface Props {
  monthlyData: Record<string, Record<number, number>>
  weeklyData: Record<string, Record<number, number>>
  totalByGroup: Record<string, number>
}

const PRODUCT_GROUPS = ['미니멀러그', '그레인러그', '시어서커', '사이잘러그', '방석/쿠션', '블랭킷']
const GROUP_COLORS: Record<string, { bg: string; text: string; border: string }> = {
  '미니멀러그': { bg: '#EEF2FF', text: '#4F46E5', border: '#C7D2FE' },
  '그레인러그': { bg: '#FEF3C7', text: '#D97706', border: '#FDE68A' },
  '시어서커': { bg: '#DBEAFE', text: '#2563EB', border: '#BFDBFE' },
  '사이잘러그': { bg: '#D1FAE5', text: '#059669', border: '#A7F3D0' },
  '방석/쿠션': { bg: '#FCE7F3', text: '#DB2777', border: '#FBCFE8' },
  '블랭킷': { bg: '#FFF7ED', text: '#EA580C', border: '#FED7AA' },
}

export default function ClientPage({ monthlyData, weeklyData, totalByGroup }: Props) {
  const [viewType, setViewType] = useState<'monthly' | 'weekly'>('monthly')
  const [selectedMonth, setSelectedMonth] = useState<number>(1) // 주간별 보기에서 선택한 월

  // 전체 합계
  const grandTotal = Object.values(totalByGroup).reduce((sum, v) => sum + v, 0)

  // 월별 데이터 (1~12월)
  const months = Array.from({ length: 12 }, (_, i) => i + 1)

  // 주차 데이터 (전체 주차 찾기)
  const allWeeks = new Set<number>()
  Object.values(weeklyData).forEach(weekMap => {
    Object.keys(weekMap).forEach(week => allWeeks.add(parseInt(week)))
  })
  const weeks = Array.from(allWeeks).sort((a, b) => a - b)

  // 월별 주차 매핑 (대략적으로 월당 4~5주)
  const getWeeksForMonth = (month: number) => {
    const startWeek = (month - 1) * 4 + 1
    const endWeek = month * 4 + 1
    return weeks.filter(w => w >= startWeek && w <= endWeek)
  }

  // 선택된 월의 주차
  const selectedWeeks = getWeeksForMonth(selectedMonth)

  return (
    <div className="space-y-6">
      {/* 제품군별 요약 카드 */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {PRODUCT_GROUPS.map(group => {
          const total = totalByGroup[group] || 0
          const ratio = grandTotal > 0 ? (total / grandTotal * 100) : 0
          const colors = GROUP_COLORS[group]

          return (
            <div
              key={group}
              className="rounded-xl p-6 border-2 shadow-sm hover:shadow-md transition-shadow"
              style={{
                background: colors.bg,
                borderColor: colors.border,
              }}
            >
              <h3 className="text-sm font-semibold mb-2" style={{ color: colors.text }}>
                {group}
              </h3>
              <div className="flex items-baseline gap-2 mb-1">
                <span className="text-3xl font-bold" style={{ color: colors.text }}>
                  {total.toLocaleString()}
                </span>
                <span className="text-sm" style={{ color: colors.text, opacity: 0.7 }}>
                  개
                </span>
              </div>
              <div className="flex items-center gap-2 mt-2">
                <div className="flex-1 h-2 bg-white/50 rounded-full overflow-hidden">
                  <div
                    className="h-full rounded-full transition-all"
                    style={{
                      width: `${ratio}%`,
                      background: colors.text,
                    }}
                  />
                </div>
                <span className="text-xs font-medium" style={{ color: colors.text }}>
                  {ratio.toFixed(1)}%
                </span>
              </div>
            </div>
          )
        })}
      </div>

      {/* 전체 합계 */}
      <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-200">
        <div className="flex items-center justify-between">
          <h3 className="text-lg font-semibold text-gray-900">2026년 전체 판매량</h3>
          <div className="flex items-baseline gap-2">
            <span className="text-3xl font-bold text-gray-900">
              {grandTotal.toLocaleString()}
            </span>
            <span className="text-sm text-gray-500">개</span>
          </div>
        </div>
      </div>

      {/* 보기 방식 선택 */}
      <div className="flex items-center gap-3">
        <button
          onClick={() => setViewType('monthly')}
          className={`px-4 py-2 rounded-lg font-medium transition-all ${
            viewType === 'monthly'
              ? 'bg-blue-600 text-white shadow-sm'
              : 'bg-white text-gray-600 border border-gray-300 hover:bg-gray-50'
          }`}
        >
          월별 보기
        </button>
        <button
          onClick={() => setViewType('weekly')}
          className={`px-4 py-2 rounded-lg font-medium transition-all ${
            viewType === 'weekly'
              ? 'bg-blue-600 text-white shadow-sm'
              : 'bg-white text-gray-600 border border-gray-300 hover:bg-gray-50'
          }`}
        >
          주간별 보기
        </button>
      </div>

      {/* 월별 테이블 */}
      {viewType === 'monthly' && (
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="bg-gray-50 border-b border-gray-200">
                  <th className="px-6 py-4 text-left text-xs font-semibold text-gray-600 uppercase tracking-wider sticky left-0 bg-gray-50">
                    제품군
                  </th>
                  {months.map(month => (
                    <th
                      key={month}
                      className="px-4 py-4 text-center text-xs font-semibold text-gray-600 uppercase tracking-wider"
                    >
                      {month}월
                    </th>
                  ))}
                  <th className="px-6 py-4 text-right text-xs font-semibold text-gray-600 uppercase tracking-wider">
                    합계
                  </th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-200">
                {PRODUCT_GROUPS.map(group => {
                  const monthlyValues = months.map(month => monthlyData[group]?.[month] || 0)
                  const rowTotal = monthlyValues.reduce((sum, v) => sum + v, 0)
                  const colors = GROUP_COLORS[group]

                  return (
                    <tr key={group} className="hover:bg-gray-50 transition-colors">
                      <td
                        className="px-6 py-4 font-semibold sticky left-0 bg-white"
                        style={{ color: colors.text }}
                      >
                        {group}
                      </td>
                      {monthlyValues.map((value, idx) => (
                        <td key={months[idx]} className="px-4 py-4 text-center text-sm text-gray-900">
                          {value > 0 ? value.toLocaleString() : '-'}
                        </td>
                      ))}
                      <td className="px-6 py-4 text-right font-semibold text-gray-900">
                        {rowTotal.toLocaleString()}
                      </td>
                    </tr>
                  )
                })}
                {/* 총합계 행 */}
                <tr className="bg-gray-100 font-semibold">
                  <td className="px-6 py-4 sticky left-0 bg-gray-100">월별 합계</td>
                  {months.map(month => {
                    const monthTotal = PRODUCT_GROUPS.reduce(
                      (sum, g) => sum + (monthlyData[g]?.[month] || 0),
                      0
                    )
                    return (
                      <td key={month} className="px-4 py-4 text-center text-gray-900">
                        {monthTotal.toLocaleString()}
                      </td>
                    )
                  })}
                  <td className="px-6 py-4 text-right text-gray-900">
                    {grandTotal.toLocaleString()}
                  </td>
                </tr>
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* 주간별 테이블 */}
      {viewType === 'weekly' && (
        <div className="space-y-4">
          {/* 월 선택 탭 */}
          <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-4">
            <div className="flex items-center gap-2 flex-wrap">
              <span className="text-sm font-semibold text-gray-700 mr-2">월 선택:</span>
              {months.map(month => {
                const monthWeeks = getWeeksForMonth(month)
                const hasData = monthWeeks.some(w =>
                  PRODUCT_GROUPS.some(g => weeklyData[g]?.[w] > 0)
                )

                if (!hasData) return null

                return (
                  <button
                    key={month}
                    onClick={() => setSelectedMonth(month)}
                    className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${
                      selectedMonth === month
                        ? 'bg-blue-600 text-white shadow-sm'
                        : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                    }`}
                  >
                    {month}월
                  </button>
                )
              })}
            </div>
          </div>

          {/* 선택된 월의 주간 테이블 */}
          <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
            <div className="px-6 py-4 bg-gray-50 border-b border-gray-200">
              <h3 className="text-lg font-semibold text-gray-900">
                {selectedMonth}월 주간별 판매량
                {selectedWeeks.length > 0 && (
                  <span className="ml-2 text-sm font-normal text-gray-500">
                    (W{selectedWeeks[0].toString().padStart(2, '0')} ~ W{selectedWeeks[selectedWeeks.length - 1].toString().padStart(2, '0')})
                  </span>
                )}
              </h3>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead>
                  <tr className="bg-gray-50 border-b border-gray-200">
                    <th className="px-6 py-4 text-left text-xs font-semibold text-gray-600 uppercase tracking-wider sticky left-0 bg-gray-50">
                      제품군
                    </th>
                    {selectedWeeks.map(week => (
                      <th
                        key={week}
                        className="px-4 py-4 text-center text-xs font-semibold text-gray-600 uppercase tracking-wider"
                      >
                        W{week.toString().padStart(2, '0')}
                      </th>
                    ))}
                    <th className="px-6 py-4 text-right text-xs font-semibold text-gray-600 uppercase tracking-wider">
                      월 합계
                    </th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-200">
                  {PRODUCT_GROUPS.map(group => {
                    const weeklyValues = selectedWeeks.map(week => weeklyData[group]?.[week] || 0)
                    const rowTotal = weeklyValues.reduce((sum, v) => sum + v, 0)
                    const colors = GROUP_COLORS[group]

                    return (
                      <tr key={group} className="hover:bg-gray-50 transition-colors">
                        <td
                          className="px-6 py-4 font-semibold sticky left-0 bg-white"
                          style={{ color: colors.text }}
                        >
                          {group}
                        </td>
                        {weeklyValues.map((value, idx) => (
                          <td key={selectedWeeks[idx]} className="px-4 py-4 text-center text-sm text-gray-900">
                            {value > 0 ? Math.round(value).toLocaleString() : '-'}
                          </td>
                        ))}
                        <td className="px-6 py-4 text-right font-semibold text-gray-900">
                          {Math.round(rowTotal).toLocaleString()}
                        </td>
                      </tr>
                    )
                  })}
                  {/* 총합계 행 */}
                  <tr className="bg-gray-100 font-semibold">
                    <td className="px-6 py-4 sticky left-0 bg-gray-100">주간 합계</td>
                    {selectedWeeks.map(week => {
                      const weekTotal = PRODUCT_GROUPS.reduce(
                        (sum, g) => sum + (weeklyData[g]?.[week] || 0),
                        0
                      )
                      return (
                        <td key={week} className="px-4 py-4 text-center text-gray-900">
                          {Math.round(weekTotal).toLocaleString()}
                        </td>
                      )
                    })}
                    <td className="px-6 py-4 text-right text-gray-900">
                      {Math.round(
                        selectedWeeks.reduce((sum, week) => {
                          return sum + PRODUCT_GROUPS.reduce(
                            (s, g) => s + (weeklyData[g]?.[week] || 0),
                            0
                          )
                        }, 0)
                      ).toLocaleString()}
                    </td>
                  </tr>
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {/* 월별 비중 차트 */}
      <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-200">
        <h3 className="text-lg font-semibold text-gray-900 mb-4">월별 제품군 비중 (%)</h3>
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr className="border-b border-gray-200">
                <th className="px-4 py-3 text-left text-sm font-semibold text-gray-600">제품군</th>
                {months.map(month => (
                  <th key={month} className="px-4 py-3 text-center text-sm font-semibold text-gray-600">
                    {month}월
                  </th>
                ))}
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-200">
              {PRODUCT_GROUPS.map(group => {
                const colors = GROUP_COLORS[group]
                return (
                  <tr key={group} className="hover:bg-gray-50">
                    <td className="px-4 py-3 font-semibold" style={{ color: colors.text }}>
                      {group}
                    </td>
                    {months.map(month => {
                      const monthTotal = PRODUCT_GROUPS.reduce(
                        (sum, g) => sum + (monthlyData[g]?.[month] || 0),
                        0
                      )
                      const groupValue = monthlyData[group]?.[month] || 0
                      const ratio = monthTotal > 0 ? (groupValue / monthTotal * 100) : 0
                      return (
                        <td key={month} className="px-4 py-3 text-center">
                          <span className="text-sm font-medium text-gray-900">
                            {ratio > 0 ? ratio.toFixed(1) + '%' : '-'}
                          </span>
                        </td>
                      )
                    })}
                  </tr>
                )
              })}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  )
}

