async function checkCushionSales() {
  console.log('🔍 방석/쿠션 판매 데이터 확인\n')

  // 2026년 전체 데이터에서 방석/쿠션 관련 product_name 조회
  const { data: salesData } = await supabase
    .from('daily_sales')
    .select(`
      product_barcode,
      sale_date,
      quantity,
      product_barcodes (
        product_name
      )
    `)
    .gte('sale_date', '2026-01-01')
    .lte('sale_date', '2026-12-31')
    .limit(10000)

  if (!salesData || salesData.length === 0) {
    console.log('❌ 판매 데이터가 없습니다.')
    return
  }

  // 방석/쿠션 필터링
  const cushionData = salesData.filter(record => {
    const productName = record.product_barcodes?.product_name || ''
    return productName.includes('방석') || productName.includes('펫쿠션') || productName.includes('쿠션')
  })

