  console.log(`🛋️  방석/쿠션: ${cushionData.length}개\n`)

  if (cushionData.length === 0) {
    console.log('⚠️  방석/쿠션 데이터가 하나도 없습니다!')
    return
  }

  // 제품별 집계
  const productSummary = {}
  cushionData.forEach(record => {
    const name = record.product_barcodes?.product_name || '알 수 없음'
    const qty = parseFloat(record.quantity || 0)

    if (!productSummary[name]) {
      productSummary[name] = { count: 0, totalQty: 0 }
    }
    productSummary[name].count++
    productSummary[name].totalQty += qty
  })

  console.log('제품별 판매 현황:\n')
  Object.entries(productSummary)
    .sort((a, b) => b[1].totalQty - a[1].totalQty)
    .forEach(([name, data]) => {
      console.log(`  ${name}`)
      console.log(`    - ${data.count}건, 총 ${Math.round(data.totalQty)}개\n`)
    })

  // 월별 집계
  const monthlySummary = {}
  cushionData.forEach(record => {
    const month = parseInt(record.sale_date.split('-')[1])
    const qty = parseFloat(record.quantity || 0)
    monthlySummary[month] = (monthlySummary[month] || 0) + qty
  })

  console.log('\n월별 방석/쿠션 판매량:\n')
  for (let m = 1; m <= 12; m++) {
    const qty = monthlySummary[m] || 0
    if (qty > 0) {
      console.log(`  ${m}월: ${Math.round(qty)}개`)
    }
  }
}

