        console.log(`  ${p.barcode} - ${p.product_name || '(이름없음)'}`)
      })
    } else {
      console.log('❌ MCS/PCS 바코드도 없습니다!')
    }
    return
  }

  // 2. 제품 목록 출력
  console.log('등록된 방석/쿠션 제품:\n')
  products.forEach(p => {
    console.log(`  ${p.barcode} - ${p.product_name}`)
  })

  // 3. 실제 판매 데이터 확인
  console.log('\n\n🔍 판매 데이터 확인\n')

  const barcodes = products.map(p => p.barcode)
  const { data: salesData, count } = await supabase
    .from('daily_sales')
    .select('product_barcode, quantity', { count: 'exact' })
    .in('product_barcode', barcodes)
    .gte('sale_date', '2026-01-01')

  console.log(`📊 방석/쿠션 판매 레코드: ${count || 0}건`)

  if (count && count > 0) {
    // 바코드별 집계
    const summary = {}
    salesData?.forEach(s => {
      const qty = parseFloat(s.quantity || 0)
      summary[s.product_barcode] = (summary[s.product_barcode] || 0) + qty
    })

    console.log('\n바코드별 판매량:\n')
    Object.entries(summary)
      .sort((a, b) => b[1] - a[1])
      .forEach(([barcode, qty]) => {
        const product = products.find(p => p.barcode === barcode)
        console.log(`  ${barcode} (${product?.product_name || '?'}): ${Math.round(qty)}개`)
      })
  }
}

