    // 바코드별 집계
    const summary = {}
    cushionProducts.forEach(p => {
      if (!summary[p.barcode]) {
        summary[p.barcode] = { name: p.name, qty: 0 }
      }
      summary[p.barcode].qty += parseFloat(p.qty || 0)
    })

