          data={PRODUCT_GROUPS.map(group => ({
            name: group,
            value: totalByGroup[group] || 0,
            color: GROUP_COLORS[group].text
          }))}
          cx="50%"
          cy="50%"
          labelLine={false}
          label={({ name, percent }) =>
            percent > 0.03 ? `${name} ${(percent * 100).toFixed(1)}%` : ''
          }
          outerRadius={120}
          fill="#8884d8"
          dataKey="value"
        >
          {PRODUCT_GROUPS.map((group, index) => (
            <Cell key={`cell-${index}`} fill={GROUP_COLORS[group].text} />
          ))}
        </Pie>
        <Tooltip
          formatter={(value: number) => value.toLocaleString() + '개'}
          contentStyle={{
            backgroundColor: 'white',
            border: '1px solid #e5e7eb',
            borderRadius: '8px',
            padding: '8px 12px'
          }}
        />
        <Legend
          verticalAlign="bottom"
          height={36}
          iconType="circle"
          formatter={(value) => <span className="text-sm">{value}</span>}
        />
